'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.evt-rel-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.evt-rel-card{background:#fff;border-radius:16px;overflow:hidden;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.evt-rel-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.evt-rel-card-border{height:4px}\n.evt-rel-card-body{padding:28px}\n.evt-rel-badge{display:inline-block;font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;padding:4px 12px;border-radius:50px;margin-bottom:12px}\n.evt-rel-card h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;line-height:1.4;margin:0 0 16px;padding:0}\n.evt-rel-meta{display:flex;flex-direction:column;gap:8px;margin-bottom:16px}\n.evt-rel-meta-item{display:flex;align-items:center;gap:6px;font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80}\n.evt-rel-meta-item svg{flex-shrink:0;stroke:#94a3b8}\n.evt-rel-link{display:inline-flex;align-items:center;gap:4px;font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;text-decoration:none;transition:opacity 0.3s ease}\n.evt-rel-link:hover{opacity:0.8}\n\n.et_pb_section .evt-rel-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .evt-rel-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .evt-rel-card h3{-webkit-font-smoothing:auto !important;margin:0 0 16px !important;padding:0 !important}\n\n@media(max-width:768px){\n  .evt-rel-grid{grid-template-columns:1fr}\n  .evt-rel-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.evt-rel-card{transition:none !important}}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="evt-hero-section">\n  <div class="evt-hero-superd" aria-hidden="true"></div>\n  <a href="/news/" class="evt-hero-back">\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>\n    Back to News &amp; Events\n  </a>\n  <span class="evt-hero-badge">Workshop</span>\n  <h1>BOI Compliance Workshop: Production-Level Reconciliation That Passes Every Audit</h1>\n  <p class="evt-hero-subtitle">A full-day, hands-on workshop where you\'ll learn exactly how production-order-level material tracking eliminates BOI supplementary taxes — featuring the Jin Hai case study.</p>\n\n  <div class="evt-hero-facts">\n    \n      <div class="evt-hero-fact">\n        <div class="evt-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n        </div>\n        <div class="evt-hero-fact-value">March 15, 2026</div>\n        <div class="evt-hero-fact-label">Saturday</div>\n      </div>\n\n      <div class="evt-hero-fact">\n        <div class="evt-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n        </div>\n        <div class="evt-hero-fact-value">09:00 – 16:00</div>\n        <div class="evt-hero-fact-label">Full Day</div>\n      </div>\n\n      <div class="evt-hero-fact">\n        <div class="evt-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n        </div>\n        <div class="evt-hero-fact-value">Bangkok</div>\n        <div class="evt-hero-fact-label">Thailand</div>\n      </div>\n\n      <div class="evt-hero-fact">\n        <div class="evt-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4-4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87"/><path d="M16 3.13a4 4 0 010 7.75"/></svg>\n        </div>\n        <div class="evt-hero-fact-value">30 Seats</div>\n        <div class="evt-hero-fact-label">Limited</div>\n      </div>\n  </div>\n\n  <a href="/demo/" class="evt-hero-cta">\n    Register Now\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n  </a>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="evt-prob-section">\n  <div class="evt-prob-inner">\n    <span class="evt-prob-label">The Challenge</span>\n    <h2 class="evt-prob-title">Your Finance Team Spends Weeks Preparing for Every BOI Audit</h2>\n  </div>\n  <div class="evt-prob-body">\n    \n    <p>If your factory holds a BOI certificate — and if you\'re a manufacturer in Thailand, you almost certainly do — your compliance team is fighting a battle every audit cycle. They\'re manually reconciling import declarations against production records, building spreadsheets outside your ERP, and hoping the numbers align.</p>\n\n    <p>The root cause is architectural: most ERP systems calculate material consumption from theoretical BOMs. But the <strong>BOI board doesn\'t audit your BOM</strong> — they audit your actual production consumption, order by order, material by material. When your system can\'t show that level of detail, the gap between theory and reality becomes supplementary tax.</p>\n\n    <p>One factory was paying over <strong>10 million baht per year</strong> in that gap. This workshop shows you exactly how they eliminated it.</p>\n    \n    <div class="evt-prob-data-card">\n      <div class="evt-prob-data-content">\n        <div class="evt-prob-data-number">10M+ THB/year</div>\n        <div class="evt-prob-data-arrow">&darr;</div>\n        <div class="evt-prob-data-number evt-prob-data-number--success">Zero</div>\n        <div class="evt-prob-data-label">Annual supplementary tax — Jin Hai Factory</div>\n      </div>\n    </div>\n    <p class="evt-prob-case-link"><a href="/blog/boi-compliance-jin-hai/">Read the full Jin Hai case study &rarr;</a></p>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="evt-out-section">\n  <div class="evt-out-inner">\n    <span class="evt-out-label">Workshop Outcomes</span>\n    <h2 class="evt-out-title">What You\'ll Be Able to Do After This Workshop</h2>\n    <div class="evt-out-grid">\n      \n    <div class="evt-out-card">\n      <div class="evt-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M9 11l3 3L22 4"/><path d="M21 12v7a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h11"/></svg>\n      </div>\n      <h3>Run a BOI reconciliation report</h3>\n      <p>Map imported bonded materials to production orders — the exact format BOI auditors expect to see.</p>\n    </div>\n\n    <div class="evt-out-card">\n      <div class="evt-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>\n      </div>\n      <h3>Identify compliance gaps in your current ERP</h3>\n      <p>Know specifically which data your system can and cannot produce for BOI filings.</p>\n    </div>\n\n    <div class="evt-out-card">\n      <div class="evt-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><rect x="4" y="2" width="16" height="20" rx="2"/><line x1="8" y1="6" x2="16" y2="6"/><line x1="8" y1="10" x2="16" y2="10"/><line x1="8" y1="14" x2="12" y2="14"/></svg>\n      </div>\n      <h3>Calculate your supplementary tax exposure</h3>\n      <p>Estimate the gap between theoretical BOM consumption and actual production usage in your factory.</p>\n    </div>\n\n    <div class="evt-out-card">\n      <div class="evt-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>\n      </div>\n      <h3>Build a BOI audit preparation checklist</h3>\n      <p>A step-by-step process your team can follow before every audit cycle — take it home and use it.</p>\n    </div>\n\n    <div class="evt-out-card">\n      <div class="evt-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>\n      </div>\n      <h3>Evaluate ERP systems for BOI readiness</h3>\n      <p>Know what questions to ask any ERP vendor about production-order-level tracking capabilities.</p>\n    </div>\n\n    <div class="evt-out-card">\n      <div class="evt-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></svg>\n      </div>\n      <h3>Present a compliance upgrade business case</h3>\n      <p>Build the ROI argument for production-level tracking using real factory data from the workshop.</p>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="evt-agd-section">\n  <div class="evt-agd-inner">\n    <span class="evt-agd-label">Full-Day Agenda</span>\n    <h2 class="evt-agd-title">A Structured Day — Not a Sales Pitch</h2>\n    <p class="evt-agd-subtitle">Every session is designed around what you\'ll take home — not what we want to sell.</p>\n  </div>\n  <div class="evt-agd-timeline">\n    \n    <div class="evt-agd-item">\n      <div class="evt-agd-time">09:00 – 09:30</div>\n      <div class="evt-agd-content">\n        <h3>Registration & Networking</h3>\n        <p>Coffee, introductions, and a quick survey of your current BOI compliance process.</p>\n      </div>\n    </div>\n\n    <div class="evt-agd-item">\n      <div class="evt-agd-time">09:30 – 10:30</div>\n      <div class="evt-agd-content">\n        <h3>Why BOI Audits Fail</h3>\n        <p>The gap between theoretical BOM consumption and actual production data — and why most ERPs can\'t bridge it.</p>\n      </div>\n    </div>\n\n    <div class="evt-agd-item evt-agd-item--break">\n      <div class="evt-agd-time">10:30 – 10:45</div>\n      <div class="evt-agd-content">\n        <h3>Coffee Break</h3>\n        \n      </div>\n    </div>\n\n    <div class="evt-agd-item">\n      <div class="evt-agd-time">10:45 – 12:00</div>\n      <div class="evt-agd-content">\n        <h3>The Jin Hai Case Study</h3>\n        <p>How one factory went from 10M+ THB/year in supplementary taxes to zero. Data walkthrough, not marketing slides.</p>\n      </div>\n    </div>\n\n    <div class="evt-agd-item evt-agd-item--break">\n      <div class="evt-agd-time">12:00 – 13:00</div>\n      <div class="evt-agd-content">\n        <h3>Networking Lunch</h3>\n        \n      </div>\n    </div>\n\n    <div class="evt-agd-item">\n      <div class="evt-agd-time">13:00 – 14:30</div>\n      <div class="evt-agd-content">\n        <h3>Hands-On: Building a Reconciliation Report</h3>\n        <p>Working with sample production data, you\'ll build the exact report format BOI auditors want to see.</p>\n      </div>\n    </div>\n\n    <div class="evt-agd-item evt-agd-item--break">\n      <div class="evt-agd-time">14:30 – 14:45</div>\n      <div class="evt-agd-content">\n        <h3>Coffee Break</h3>\n        \n      </div>\n    </div>\n\n    <div class="evt-agd-item">\n      <div class="evt-agd-time">14:45 – 15:30</div>\n      <div class="evt-agd-content">\n        <h3>Assessing Your Current System</h3>\n        <p>Framework for evaluating whether your ERP can produce production-order-level tracking — and what to do if it can\'t.</p>\n      </div>\n    </div>\n\n    <div class="evt-agd-item">\n      <div class="evt-agd-time">15:30 – 16:00</div>\n      <div class="evt-agd-content">\n        <h3>Q&A + Next Steps</h3>\n        <p>Open discussion, individual compliance questions, and your take-home checklist.</p>\n      </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="evt-per-section">\n  <div class="evt-per-inner">\n    <span class="evt-per-label">Who This Is For</span>\n    <h2 class="evt-per-title">Is This Workshop Right for You?</h2>\n    <div class="evt-per-grid">\n      \n    <div class="evt-per-card">\n      <div class="evt-per-accent"></div>\n      <div class="evt-per-body">\n        <div class="evt-per-role">Factory CFO / Finance Director</div>\n        <span class="evt-per-size">50-500 Employees, BOI-Certified</span>\n        <p class="evt-per-desc">You sign off on BOI compliance filings and worry about audit results every cycle. You need to understand your factory\'s compliance exposure.</p>\n        <p class="evt-per-quote">"I need to know our compliance exposure — and whether our ERP is hiding gaps."</p>\n      </div>\n    </div>\n\n    <div class="evt-per-card">\n      <div class="evt-per-accent"></div>\n      <div class="evt-per-body">\n        <div class="evt-per-role">Production Manager / Plant Manager</div>\n        <span class="evt-per-size">Any Size, BOI-Certified</span>\n        <p class="evt-per-desc">You run the shop floor and your data feeds the compliance reports. Production accuracy directly impacts your factory\'s BOI standing.</p>\n        <p class="evt-per-quote">"I need my production data to match what finance reports — but right now it doesn\'t."</p>\n      </div>\n    </div>\n\n    <div class="evt-per-card">\n      <div class="evt-per-accent"></div>\n      <div class="evt-per-body">\n        <div class="evt-per-role">ERP / IT Manager</div>\n        <span class="evt-per-size">Evaluating or Upgrading ERP</span>\n        <p class="evt-per-desc">You manage the system that\'s supposed to produce BOI reports. You need to know what production-order-level tracking actually requires.</p>\n        <p class="evt-per-quote">"I need to know what production-order-level tracking actually requires from a system."</p>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="evt-prf-section">\n  <div class="evt-prf-inner">\n    <span class="evt-prf-label">Why DigiWin Events</span>\n    <h2 class="evt-prf-title">Learn from the Team That\'s Done This 100+ Times</h2>\n    <div class="evt-prf-stats-bar">\n      \n    <div class="evt-prf-stat">\n      <div class="evt-prf-stat-value">100+</div>\n      <div class="evt-prf-stat-label">Thai Implementations</div>\n    </div>\n\n    <div class="evt-prf-stat">\n      <div class="evt-prf-stat-value">44</div>\n      <div class="evt-prf-stat-label">Years Manufacturing ERP</div>\n    </div>\n\n    <div class="evt-prf-stat">\n      <div class="evt-prf-stat-value">95%</div>\n      <div class="evt-prf-stat-label">Contract Renewal Rate</div>\n    </div>\n\n    <div class="evt-prf-stat">\n      <div class="evt-prf-stat-value">50+</div>\n      <div class="evt-prf-stat-label">Thai Team Members</div>\n    </div>\n    </div>\n    <p class="evt-prf-text">DigiWin has been helping Thai manufacturers pass BOI audits for 8 years. This workshop distills that experience into a single day — the same frameworks our implementation team uses with every BOI-certified client.</p>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="evt-log-section">\n  <div class="evt-log-inner">\n    <span class="evt-log-label">Practical Details</span>\n    <h2 cl